+#[must_use]
+fn scan_double_quotes_for_heredoc(
+    command: &str,
+    start: usize,
+    recursion_depth: usize,
+) -> (bool, usize) {
+    if recursion_depth > 500 {
+        return (true, command.len());
+    }
+
+    let bytes = command.as_bytes();
+    let len = bytes.len();
+    let mut i = start.min(len);
+
+    while i < len {
+        match bytes[i] {
+            b'"' => return (false, i + 1),
+            b'\\' => {
+                i = (i + 2).min(len);
+            }
+            b'$' if i + 1 < len && bytes[i + 1] == b'(' => {
+                let (found, next) =
+                    scan_dollar_paren_for_heredoc_recursive(command, i, recursion_depth + 1);
+                if found {
+                    return (true, next);
+                }
+                i = next;
+            }
+            b'`' => {
+                let (found, next) =
+                    scan_backticks_for_heredoc_recursive(command, i, recursion_depth + 1);
+                if found {
+                    return (true, next);
+                }
+                i = next;
+            }
+            _ => {
+                i += 1;
+            }
+        }
+    }
+
+    (false, len)
+}
+
+#[must_use]
+fn scan_dollar_paren_for_heredoc_recursive(
+    command: &str,
+    start: usize,
+    recursion_depth: usize,
+) -> (bool, usize) {
+    // Prevent stack overflow on pathological input.
+    if recursion_depth > 500 {
+        return (true, command.len());
+    }
+
+    let bytes = command.as_bytes();
+    let len = bytes.len();
+
+    debug_assert!(bytes.get(start) == Some(&b'$'));
+    debug_assert!(bytes.get(start + 1) == Some(&b'('));
+
+    let mut i = start + 2;
+    let mut depth: u32 = 1;
+
+    while i < len {
+        match bytes[i] {
+            b'<' if i + 1 < len && bytes[i + 1] == b'<' => {
+                return (true, i + 2);
+            }
+            b'(' => {
+                depth += 1;
+                i += 1;
+            }
+            b')' => {
+                if depth == 1 {
+                    // End of command substitution.
+                    return (false, i + 1);
+                }
+                depth = depth.saturating_sub(1);
+                i += 1;
+            }
+            b'\\' => {
+                i = (i + 2).min(len);
+            }
+            b'\'' => {
+                // Single quotes inside: consume until closing.
+                i += 1;
+                while i < len && bytes[i] != b'\'' {
+                    i += 1;
+                }
+                if i < len {
+                    i += 1;
+                }
+            }
+            b'"' => {
+                let (found, next) = scan_double_quotes_for_heredoc(command, i + 1, recursion_depth);
+                if found {
+                    return (true, next);
+                }
+                i = next;
+            }
+            b'$' if i + 1 < len && bytes[i + 1] == b'(' => {
+                let (found, next) =
+                    scan_dollar_paren_for_heredoc_recursive(command, i, recursion_depth + 1);
+                if found {
+                    return (true, next);
+                }
+                i = next;
+            }
+            b'`' => {
+                let (found, next) =
+                    scan_backticks_for_heredoc_recursive(command, i, recursion_depth + 1);
+                if found {
+                    return (true, next);
+                }
+                i = next;
+            }
+            _ => {
+                i += 1;
+            }
+        }
+    }
+
+    (false, len)
+}
