+                return (true, i + 2);
+            }
+            b'\\' => {
+                i = (i + 2).min(len);
+            }
+            b'\'' => {
+                i += 1;
+                while i < len && bytes[i] != b'\'' {
+                    i += 1;
+                }
+                if i < len {
+                    i += 1;
+                }
+            }
+            b'"' => {
+                let (found, next) = scan_double_quotes_for_heredoc(command, i + 1, recursion_depth);
+                if found {
+                    return (true, next);
+                }
+                i = next;
+            }
+            b'$' if i + 1 < len && bytes[i + 1] == b'(' => {
